hooks.onInit:
var s = world.state;
var COLS = 7, ROWS = 4;
var X0 = 210, DX = 90, Y0 = 175, DY = 80;
s.zero = 1 * COLS + 3;            // caso cero: fila 1, columna 3 (centro-arriba)
s.R0 = 2;
s.showR0 = 0; s.showCount = 0; s.count = 0;
s.sim = false; s.formulaOn = 0;

// Colores de estado.
s.C_SANO = '#d8a878';
s.C_INF = '#c9463a';
s.C_REC = '#8a94a8';
s.C_VAX = '#4f86d6';
s.C_SHIELD = '#a9cbf0';

// (Re)construye la comunidad sana. Jitter determinista por índice (sin rng),
// así el replay reproduce exactamente la misma malla.
s.build = function () {
  var p = [];
  for (var r = 0; r < ROWS; r++) {
    for (var c = 0; c < COLS; c++) {
      var i = r * COLS + c;
      var jx = Math.sin(i * 12.9898) * 7;
      var jy = Math.cos(i * 4.1414) * 6;
      p.push({
        x: X0 + c * DX + jx,
        y: Y0 + r * DY + jy,
        st: 0,        // 0 sano, 1 infectado, 2 recuperado
        vax: false,
        it: 0,        // segundos desde que se infectó
        fired: false, // ya lanzó sus contagios
        ph: i * 0.7,  // fase de respiración
      });
    }
  }
  s.people = p;
  s.edges = [];
  s.count = 0;
};

// Infecta al caso cero.
s.seed = function (idx) {
  var q = s.people[idx];
  if (q) { q.st = 1; q.it = 0; q.fired = false; s.count = 1; }
};

// Inmuniza a la mitad de la población formando una MURALLA alrededor del foco:
// deja sanos unos pocos vecinos inmediatos del caso cero (el combustible que
// arrancará el brote), inmuniza la franja siguiente (el cinturón que lo
// contiene) y deja sanos a los lejanos (protegidos por el rebaño, aunque no
// estén vacunados: esa es la joya de la inmunidad de grupo). Total ~50%, el
// umbral teórico 1 - 1/R0 = 0.5 para R0 = 2.
s.vaccinate = function (frac) {
  var zero = s.people[s.zero];
  var order = [];
  for (var i = 0; i < s.people.length; i++) {
    if (i === s.zero) continue;
    var d = Math.hypot(s.people[i].x - zero.x, s.people[i].y - zero.y);
    order.push({ i: i, d: d });
  }
  order.sort(function (a, b) { return a.d - b.d; });
  var FUEL = 3;                                   // sanos cercanos (combustible)
  var wall = Math.round(s.people.length * (frac == null ? 0.5 : frac));
  for (var k = FUEL; k < FUEL + wall && k < order.length; k++) {
    s.people[order[k].i].vax = true;
  }
};

// El ícono del virus (prop v0) sobre la cabeza del caso cero.
s.showVirus = function () {
  var z = s.people[s.zero];
  var v = world.props.find(function (q) { return q.id === 'v0'; });
  if (v && z) { v.x = z.x; v.y = z.y - 46; world.tween(v, 'alpha', 1, { duration: 0.7 }); world.tween(v, 'glow', 1, { duration: 1.2 }); }
};
s.hideVirus = function () {
  var v = world.props.find(function (q) { return q.id === 'v0'; });
  if (v) { world.tween(v, 'alpha', 0, { duration: 0.6 }); world.tween(v, 'glow', 0, { duration: 0.6 }); }
};

s.build();

hooks.onStep:
var s = world.state;
if (!s.people) return;
var FIRE_DELAY = 0.55;   // s desde infectarse hasta lanzar contagios
var EDGE_TIME = 0.5;     // s que tarda una línea de contagio en cruzar
var RADIUS = 132;        // alcance de contagio (cubre vecinos cercanos)

// Avanzar las líneas de contagio en vuelo.
if (s.edges) {
  for (var e = 0; e < s.edges.length; e++) {
    var ed = s.edges[e];
    if (ed.done) { ed.age = (ed.age || 0) + dt; continue; }
    ed.p += dt / EDGE_TIME;
    if (ed.p >= 1) {
      ed.p = 1; ed.done = true; ed.age = 0;
      var tgt = s.people[ed.to];
      if (tgt && !ed.blocked && tgt.st === 0 && !tgt.vax) {
        tgt.st = 1; tgt.it = 0; tgt.fired = false;
        s.count = (s.count || 0) + 1;
        world.fx.particles(tgt.x, tgt.y, { count: 8, color: '#e0663a', speed: 60, duration: 0.7, size: 2, spread: 6.28 });
      } else if (ed.blocked) {
        world.fx.particles(ed.hx, ed.hy, { count: 7, color: '#a9cbf0', speed: 55, duration: 0.6, size: 2, spread: 6.28 });
      }
    }
  }
  // descartar líneas resueltas tras un breve resplandor
  s.edges = s.edges.filter(function (x) { return !(x.done && x.age > 0.45); });
}

if (!s.sim) return;

// Propagación: cada infectado que ya cumplió su retardo lanza hasta R0
// contagios hacia los vecinos sanos-no-vacunados más cercanos; si en su
// radio solo quedan vacunados, la línea sale igual y rebota en el escudo (la
// cadena se ve chocar y detenerse).
for (var i = 0; i < s.people.length; i++) {
  var p = s.people[i];
  if (p.st !== 1) continue;
  p.it += dt;   // reloj del infectado (alimenta el pulso de recién contagiado)
  // Sin recuperación automática: el infectado queda rojo toda la escena, para
  // que la marea del brote (y su contraste con la contención) se LEA en cada
  // foto. Deja de contagiar por sí solo cuando ya disparó (fired).
  if (p.fired || p.it < FIRE_DELAY) continue;
  p.fired = true;
  // candidatos: sanos aún no reservados por otra línea, más los vacunados
  // cercanos (posibles choques) si no hay sanos suficientes.
  var open = [], shields = [];
  for (var j = 0; j < s.people.length; j++) {
    if (j === i) continue;
    var q = s.people[j];
    var d = Math.hypot(q.x - p.x, q.y - p.y);
    if (d > RADIUS) continue;
    if (q.st === 0 && !q.vax && !q._targeted) open.push({ j: j, d: d });
    else if (q.vax) shields.push({ j: j, d: d });
  }
  open.sort(function (a, b) { return a.d - b.d; });
  shields.sort(function (a, b) { return a.d - b.d; });
  var picks = [];
  for (var o = 0; o < open.length && picks.length < s.R0; o++) picks.push({ j: open[o].j, vax: false });
  // completar el cupo de R0 con escudos cercanos (la cadena choca y se ve)
  for (var sh = 0; sh < shields.length && picks.length < s.R0; sh++) picks.push({ j: shields[sh].j, vax: true });
  for (var c = 0; c < picks.length; c++) {
    var q2 = s.people[picks[c].j];
    var ang = Math.atan2(q2.y - p.y, q2.x - p.x);
    var stopR = picks[c].vax ? 27 : 15;
    var hx = q2.x - Math.cos(ang) * stopR;
    var hy = q2.y - Math.sin(ang) * stopR;
    s.edges.push({ fx: p.x, fy: p.y, to: picks[c].j, p: 0, done: false, blocked: picks[c].vax, hx: hx, hy: hy });
    if (!picks[c].vax) q2._targeted = true;
  }
}

hooks.onDraw:
var s = world.state;
if (!s.people) return;
var T = world.t;
var UIQ = '"Plus Jakarta Sans", ui-sans-serif, system-ui, sans-serif';

// --- líneas de contagio (debajo de la gente) ---
if (s.edges) {
  for (var e = 0; e < s.edges.length; e++) {
    var ed = s.edges[e];
    var ex = ed.fx + (ed.hx - ed.fx) * Math.min(1, ed.p);
    var ey = ed.fy + (ed.hy - ed.fy) * Math.min(1, ed.p);
    ctx.save();
    var fade = ed.done ? Math.max(0, 1 - (ed.age || 0) / 0.45) : 1;
    ctx.globalAlpha = 0.9 * fade;
    ctx.strokeStyle = ed.blocked ? '#7fa8dc' : '#d8543f';
    ctx.lineWidth = 2.4;
    ctx.lineCap = 'round';
    if (ed.blocked) ctx.setLineDash([4, 4]);
    ctx.beginPath();
    ctx.moveTo(ed.fx, ed.fy);
    ctx.lineTo(ex, ey);
    ctx.stroke();
    ctx.setLineDash([]);
    // cabeza de la línea en vuelo
    if (!ed.done) {
      ctx.fillStyle = ed.blocked ? '#a9cbf0' : '#f0784f';
      ctx.beginPath(); ctx.arc(ex, ey, 3.2, 0, 6.283); ctx.fill();
    }
    ctx.restore();
  }
}

// --- personas ---
var HW = 13, HH = 15;
for (var i = 0; i < s.people.length; i++) {
  var p = s.people[i];
  var breath = Math.sin(T * 1.6 + p.ph) * 1.1;
  var cx = p.x, cy = p.y + breath;
  var col = s.C_SANO;
  if (p.vax && p.st !== 1) col = s.C_VAX;
  if (p.st === 1) col = s.C_INF;
  else if (p.st === 2) col = s.C_REC;

  // escudo de vacunado
  if (p.vax && p.st !== 1) {
    var sp = 0.5 + 0.5 * Math.sin(T * 2.2 + p.ph);
    ctx.save();
    ctx.globalAlpha = 0.32 + 0.16 * sp;
    ctx.strokeStyle = s.C_SHIELD;
    ctx.lineWidth = 2.2;
    ctx.beginPath(); ctx.arc(cx, cy - 1, HW + 8, 0, 6.283); ctx.stroke();
    ctx.globalAlpha = 0.10 + 0.06 * sp;
    ctx.fillStyle = s.C_SHIELD;
    ctx.beginPath(); ctx.arc(cx, cy - 1, HW + 8, 0, 6.283); ctx.fill();
    ctx.restore();
  }

  // pulso de recién infectado
  if (p.st === 1 && p.it < 0.9) {
    var pr = p.it / 0.9;
    ctx.save();
    ctx.globalAlpha = (1 - pr) * 0.5;
    ctx.strokeStyle = s.C_INF; ctx.lineWidth = 2.5;
    ctx.beginPath(); ctx.arc(cx, cy - 1, HW + 4 + pr * 16, 0, 6.283); ctx.stroke();
    ctx.restore();
  }

  // sombra de contacto
  ctx.fillStyle = 'rgba(20,24,38,0.16)';
  ctx.beginPath(); ctx.ellipse(p.x, p.y + HH - 1, HW * 0.82, 3.2, 0, 0, 6.283); ctx.fill();

  // cuerpo
  world.draw.rrect(cx - HW, cy - HH, HW * 2, HH * 2, 10);
  ctx.fillStyle = col; ctx.fill();
  // panza (tono claro)
  ctx.fillStyle = 'rgba(255,255,255,0.14)';
  world.draw.rrect(cx - HW, cy + 1, HW * 2, HH - 2, 8); ctx.fill();
  // ojos
  var ee = p.st === 1 ? 3.4 : 3.0;
  ctx.fillStyle = '#fbfaf6';
  ctx.beginPath(); ctx.arc(cx - 4.6, cy - 4, ee, 0, 6.283); ctx.fill();
  ctx.beginPath(); ctx.arc(cx + 4.6, cy - 4, ee, 0, 6.283); ctx.fill();
  ctx.fillStyle = '#20242f';
  var pd = 1.5;
  ctx.beginPath(); ctx.arc(cx - 4.6, cy - 3.4, pd, 0, 6.283); ctx.fill();
  ctx.beginPath(); ctx.arc(cx + 4.6, cy - 3.4, pd, 0, 6.283); ctx.fill();
  // boca preocupada del infectado
  if (p.st === 1) {
    ctx.strokeStyle = '#5a1a14'; ctx.lineWidth = 1.4; ctx.lineCap = 'round';
    ctx.beginPath(); ctx.arc(cx, cy + 6, 3, Math.PI * 1.15, Math.PI * 1.85); ctx.stroke();
  }
}

// --- contador exponencial ---
if (s.showCount > 0.01) {
  ctx.save();
  ctx.globalAlpha = Math.min(1, s.showCount);
  ctx.textAlign = 'center';
  ctx.fillStyle = '#c9463a';
  ctx.font = '700 44px ' + UIQ;
  ctx.fillText(String(s.count || 0), world.W / 2, 92);
  ctx.fillStyle = '#6E7896';
  ctx.font = '600 12px ' + UIQ;
  ctx.fillText('CONTAGIADOS', world.W / 2, 110);
  ctx.restore();
}

// --- etiqueta R0 sobre el caso cero ---
if (s.showR0 > 0.01) {
  var z = s.people[s.zero];
  ctx.save();
  ctx.globalAlpha = Math.min(1, s.showR0);
  ctx.textAlign = 'center';
  ctx.fillStyle = '#1F2547';
  world.draw.rrect(z.x - 46, z.y - 78, 92, 26, 7); ctx.fill();
  ctx.fillStyle = '#F4AC1D';
  ctx.font = '700 15px ' + UIQ;
  ctx.textBaseline = 'middle';
  ctx.fillText('R₀ = ' + (s.R0 || 2), z.x, z.y - 64);
  ctx.restore();
}
